"async function syncCartBadge() {
    const cartId = await getOrCreateCartId();
    const { data: items, error } = await supabase
        .from('cart_items')
        .select('quantity')
        .eq('cart_id', cartId);

    if (error) {
        console.error('Error fetching cart items count:', error);
        return;
    }

    const totalQty = items ? items.reduce((sum, item) => sum + (item.quantity || 0), 0) : 0;

    const cartIcons = document.querySelectorAll('.material-symbols-outlined');
    let cartLink = null;
    for (let icon of cartIcons) {
        const text = icon.textContent.trim();
        if (text === 'shopping_cart' || text === 'shopping_bag') {
            if (icon.tagName === 'A') {
                cartLink = icon;
            } else if (icon.parentElement && icon.parentElement.tagName === 'A') {
                cartLink = icon.parentElement;
            } else {
                cartLink = icon;
            }
            break;
        }
    }

    if (cartLink) {
        cartLink.style.position = 'relative';
        let badge = cartLink.querySelector('.cart-badge');
        if (!badge) {
            badge = document.createElement('span');
            badge.className = 'cart-badge absolute -top-2 -right-2 bg-secondary text-white font-label-sm text-[10px] rounded-full flex items-center justify-center border border-surface';
            badge.style.width = '18px';
            badge.style.height = '18px';
            badge.style.lineHeight = '18px';
            cartLink.appendChild(badge);
        }

        if (totalQty > 0) {
            badge.textContent = totalQty;
            badge.classList.remove('hidden');
        } else {
            badge.classList.add('hidden');
        }
    }
}"

